import { Component, OnInit } from "@angular/core";
import { DatePipe, formatNumber } from "@angular/common";
import {
  FormBuilder,
  FormControl,
  FormGroup,
  Validators,
} from "@angular/forms";
import { HttpClient } from "@angular/common/http";
import { EnvService } from "src/app/core/services/env.service";
import { AlertService } from "src/app/core/services/alert.service";
import { Tree, Node } from "src/app/views/Models/Users/Tree";
import { FundRef, Funder } from "src/app/views/Models/Settings/Funder";
import { InputMaskingService } from "src/app/core/services/input-masking.service";

@Component({
  selector: "app-funder-sources",
  templateUrl: "./funder-sources.page.html",
  styleUrls: ["./funder-sources.page.scss"],
})
export class FunderSourcesPage implements OnInit {
  showLoader: boolean = false;
  isSubmitted: boolean = false;
  isInserting: boolean = false;
  isEditing: boolean = false;
  isAdd: boolean = false;
  isAdding: boolean = false;
  isUpdating: boolean = false;
  isEditingOld: boolean = false;
  isAddition: boolean = false;
  TreeNodes: Tree<Node>[];
  currentTreeNode: Tree<Node>;
  funderInfo: Funder;
  funder: Funder[];

  hasSupervisor: boolean = false;
  sortingIconClass: string;
  sortingIconParam: string;
  FundRef: FundRef[];
  FundRefInfo: FundRef;
  FundForm: FormGroup = this.formBuilder.group({
    tree_code: [""],
    tree_name: ["", [Validators.required]],
    active_rec: [""],
    fees_perc: ["", [Validators.required]],
    export_data: [""],
    iscore_external_funding: [""],
  });
  FundRefForm: FormGroup = this.formBuilder.group({
    funding_reference_id: [""],
    funder_code: [""],
    funding_reference_code: [""],
    funding_amount: ["", [Validators.required]],
    funding_date: ["", [Validators.required]],
  });
  RefForm: FormGroup = this.formBuilder.group({
    funding_reference_id: [""],
    funder_code: [""],
    funding_reference_code: [""],
    funding_amount: ["", [Validators.required]],
    funding_date: ["", [Validators.required]],
  });
  noWhitespaceValidator(control: FormControl) {
    const isWhitespace =
      control.value !== null &&
      (control.value || "").toString().trim().length === 0;
    const isValid = !isWhitespace;
    return isValid ? null : { whitespace: true };
  }
  constructor(
    private formBuilder: FormBuilder,
    private datepipe: DatePipe,
    private http: HttpClient,
    private env: EnvService,
    private alertServices: AlertService,
    public inputMaskingService: InputMaskingService
  ) {}

  ngOnInit() {
    this.FunderReasons();
  }
  FunderReasons() {
    this.showLoader = true;
    this.TreeNodes = [
      {
        data: {
          node_code: 0,
          active_rec: null,
          parent_id: null,
        },
        collapsed: true,
        text: "مصادر التمويل",
        canEdit: false,
        canDelete: false,
        canAdd: true,
        canSelect: false,
        initialized: false,
      },
    ];
    this.http
      .get<Funder[]>(this.env.API_URL + "api/Settings/GetAllFunder")
      .subscribe({
        next: (Funds_1) => {
          this.TreeNodes = this.TreeNodes.map((treeNode) => ({
            ...treeNode,
            children: Funds_1.filter(
              (Fund) => treeNode.data.node_code == 0
            ).map<Tree<Node>>((Fund) => ({
              data: {
                org_code: parseInt(Fund.org_code),
                node_code: parseInt(Fund.funder_code),
                active_rec: Fund.active_rec,
                parent_id: 0,
              },
              text: Fund.funder_name,
              initialized: false,
              collapsed: true,
              canEdit: true,
              canDelete: true,
              canSelect: false,
              canAdd: false,
            })),
          }));
          this.showLoader = false;
        },
      });
  }
  Edit(tree: Tree<Node>): void {
    this.hasSupervisor = false;
    this.currentTreeNode = tree;
    if (tree.data.parent_id != null && !tree.children) {
      this.GetFundByID(tree.data.node_code, true, true);
      this.GetFundRefByID(tree.data.node_code, true);
    }
  }
  async Delete(node: Tree<Node>): Promise<void> {
    this.hasSupervisor = false;
    this.currentTreeNode = node;
    if (await this.alertServices.SaveAlert("هل تريد الحذف؟")) {
      if (node.data.parent_id != null && !node.children) {
        this.showLoader = true;
        this.http
          .post(`${this.env.API_URL}api/Settings/GetFunderDelete`, {
            funder_code: node.data.node_code.toString(),
          })
          .subscribe({
            next: (data) => {
              this.showLoader = false;
              this.alertServices.showAlertConfirm("تم الحذف بنجاح", true);
            },
            error: (err) => {
              console.log(err);
              this.alertServices.showAlertError(err.error, false);
              this.showLoader = false;
            },
          });
      }
    }
  }
  Add(node: Tree<Node>): void {
    this.currentTreeNode = node;
    if (node.data.parent_id == null && node.children) {
      this.GetFundInsert(true);
    }
  }
  async GetFundByID(funder_code, isEditing, isInserting) {
    this.http
      .get<Funder>(
        `${this.env.API_URL}api/Settings/GetFunder?funderCode=${funder_code}`
      )

      .subscribe({
        next: (data) => {
          this.funderInfo = data;
          if (isEditing) this.patchDataValue();
          this.isEditing = isEditing;
          this.isInserting = isInserting;
          this.isEditingOld = this.isEditingOld;
          this.showLoader = false;
        },

        error: (err) => {
          console.log(err);
          this.showLoader = false;
        },
      });
  }
  patchDataValue() {
    this.FundForm.patchValue({
      tree_name: this.funderInfo[0].funder_name,
      tree_code: this.funderInfo[0].funder_code,
      active_rec: this.funderInfo[0].active_rec,
      fees_perc: this.funderInfo[0].fees_perc,
      export_data: this.funderInfo[0].export_data,
      iscore_external_funding: this.funderInfo[0].iscore_external_funding,
    });
  }
  async GetFundInsert(isAdd) {
    if (isAdd) this.FundInsert();
    this.isAdd = isAdd;
    this.showLoader = false;
  }
  FundInsert() {
    this.FundForm.patchValue({
      tree_name: " ",
      tree_code: 0,
      active_rec: 0,
      fees_perc: 0,
      export_data: 0,
      iscore_external_funding: 0,
    });
  }
  clearForms() {
    this.isInserting = false;
    this.isEditing = false;
    this.isSubmitted = false;
    this.isAdd = false;
    this.isAdding = false;
    this.isUpdating = false;
    this.isEditingOld = false;
    this.isAddition = false;
    this.FundForm.reset();
    this.RefForm.reset();
    this.FundRefForm.reset();
  }
  clear() {
    this.isAdding = false;
    this.isUpdating= false;
    this.isAddition = true;
    this.isEditingOld = true;
    this.RefForm.reset();
    
  }
  async EditFund() {
    let node: Tree<Node> = this.currentTreeNode;
    if (this.FundForm.valid) {
      if (await this.alertServices.SaveAlert("هل تريد تعديل البيانات؟")) {
        this.showLoader = true;
        this.http
          .post(this.env.API_URL + "api/Settings/GetFunderUpdate", {
            funder_code: node.data.node_code.toString(),
            funder_name: this.FundForm.value.tree_name.toString(),
            active_rec: this.FundForm.value.active_rec == 1 ? 1 : 0,
            fees_perc: this.FundForm.value.fees_perc.toString(),
            export_data: this.FundForm.value.export_data == 1 ? 1 : 0,
            iscore_external_funding:
              this.FundForm.value.iscore_external_funding == 1 ? 1 : 0,
          })
          .subscribe({
            next: (data) => {
              this.showLoader = false;
              this.alertServices.showAlertConfirm("تم الحفظ بنجاح", true);
            },
            error: (err) => {
              console.log(err);
              this.alertServices.showAlertError(err.error, false);
              this.showLoader = false;
            },
          });
      }
    }
  }
  async InsertFund() {
    let node: Tree<Node> = this.currentTreeNode;
    if (this.FundForm.valid) {
      if (await this.alertServices.SaveAlert("هل تريد الاضافة؟")) {
        this.showLoader = true;
        this.http
          .post(this.env.API_URL + "api/Settings/GetFunderInsert", {
            funder_name: this.FundForm.value.tree_name.toString(),
            active_rec: this.FundForm.value.active_rec == 1 ? 1 : 0,
            fees_perc: this.FundForm.value.fees_perc.toString(),
            export_data: this.FundForm.value.export_data == 1 ? 1 : 0,
            iscore_external_funding:
              this.FundForm.value.iscore_external_funding == 1 ? 1 : 0,
          })
          .subscribe({
            next: (data) => {
              this.showLoader = false;
              this.alertServices.showAlertConfirm("تم الحفظ بنجاح", true);
            },
            error: (err) => {
              console.log(err);
              this.alertServices.showAlertError(err.error, false);
              this.showLoader = false;
            },
          });
      }
    } else {
      this.alertServices.showAlertError("يجب ادخال جميع البيانات", false);
    }
  }
  updateFundRef(index: number) {
    const FundRef = this.FundRef[index];
    this.RefForm.patchValue({
      funding_reference_id: FundRef.funding_reference_id,
      funder_code: FundRef.funder_code,
      funding_reference_code: FundRef.funding_reference_code,
      funding_amount: FundRef.funding_amount,
      funding_date: FundRef.funding_date,
    });
    this.isAdding = false;
    this.isUpdating = true;
  }
  insertFundRef() {
    this.isAdding = true;
    this.RefForm.reset();
    this.isUpdating = false;
  }
  async submitRefInsert() {
    try {
      let node: Tree<Node> = this.currentTreeNode;
      if (this.RefForm.valid) {
        if (await this.alertServices.SaveAlert("هل تريد الاضافة؟")) {
          this.http
            .post(this.env.API_URL + "api/Settings/GetFunderRefIns", {
              funder_code: node.data.node_code.toString(),
              funding_reference_code:
                this.RefForm.value.funding_reference_code.toString(),
              funding_amount: this.RefForm.value.funding_amount.toString(),
              funding_date: this.RefForm.value.funding_date.toString(),
            })
            .subscribe({
              next: (data) => {
                this.showLoader = false;
                this.alertServices.showAlertConfirm("تم الحفظ بنجاح", true);
              },
              error: (err) => {
                console.log(err);
                this.alertServices.showAlertError(err.error, false);
                this.showLoader = false;
              },
            });
        }
      } else {
        this.alertServices.showAlertError("يجب ادخال جميع البيانات", false);
      }
    } catch {}
  }
  async submitRefUpdate() {
    let node: Tree<Node> = this.currentTreeNode;
    if (this.RefForm.valid) {
      if (await this.alertServices.SaveAlert("هل تريد تعديل البيانات؟")) {
        this.http
          .post(this.env.API_URL + "api/Settings/GetFunderRefUpd", {
            funder_code: node.data.node_code.toString(),
            funding_reference_id:
              this.RefForm.value.funding_reference_id.toString(),
            funding_reference_code:
              this.RefForm.value.funding_reference_code.toString(),
            funding_amount: this.RefForm.value.funding_amount.toString(),
            funding_date: this.RefForm.value.funding_date.toString(),
          })
          .subscribe({
            next: (data) => {
              this.showLoader = false;
              this.alertServices.showAlertConfirm("تم الحفظ بنجاح", true);
            },
            error: (err) => {
              console.log(err);
              this.alertServices.showAlertError(err.error, false);
              this.showLoader = false;
            },
          });
      }
    } else {
      this.alertServices.showAlertError("يجب ادخال جميع البيانات", false);
    }
  }

  GetFundRefByID(funder_code, isEditingOld) {
    this.http
      .get<FundRef[]>(
        `${this.env.API_URL}api/Settings/GetFunderRef?funderCode=${funder_code}`
      )

      .subscribe({
        next: (data) => {
          this.FundRef = data;
          this.isEditingOld = isEditingOld;
          this.showLoader = false;
        },
        error: (err) => {
          console.log(err);
          this.showLoader = false;
        },
      });
  }
}
